import { cn } from "@/lib/utils";

/**
 * Nodrat brand assets — inline SVG component.
 *
 * Variants:
 *   - "mark":     square symbol (favicon.svg, 29x29) — bright teal #00F2B1
 *   - "wordmark": horizontal "nodrat" text (logo.svg, 85x16) — currentColor
 *
 * Dark/light mode:
 *   - mark: brand teal renk her iki modda da görünür (sabit #00F2B1)
 *   - wordmark: fill=currentColor → text-foreground'tan miras alır
 *     (light mode = koyu, dark mode = açık)
 *
 * Sizes (height baz):
 *   - sm: 20px
 *   - md: 28px (default)
 *   - lg: 40px
 *
 * Tone prop geriye dönük uyumluluk için tutuldu (mark için inverse =
 * cooler beyaz; default = brand teal).
 *
 * a11y: role="img" + aria-label = "Nodrat"
 */
type LogoVariant = "wordmark" | "mark";
type LogoSize = "sm" | "md" | "lg";
type LogoTone = "default" | "inverse";

interface LogoProps {
  variant?: LogoVariant;
  size?: LogoSize;
  tone?: LogoTone;
  className?: string;
}

const SIZE_HEIGHT: Record<LogoSize, number> = {
  sm: 20,
  md: 28,
  lg: 40,
};

